      "moduleLabel": "CCNA 1 Version 7.00: ITNv7 Practice Final Exam",
      "moduleShortLabel": "CCNA1 Final",
      "questionNumber": 54,
      "type": "single",
      "promptHtml": "<p><strong>Refer to the exhibit. What is the maximum possible throughput between the PC and the server?</strong><br />\n<img src=\"assets/exhibits/ccna1-final-practice/q054-1-2530c9ddb7.png\" alt=\"\" /></p>",
      "promptText": "Refer to the exhibit. What is the maximum possible throughput between the PC and the server?",
