      "type": "multiple",
      "promptHtml": "<p><strong>Match the octal value to the file permission description in Linux. (Not all options are used.)</strong><br />\n<img src=\"assets/exhibits/iao-m3-4/q012-1-a4da38b198.png\" alt=\"\" /></p>",
