      "type": "study",
      "promptHtml": "<p><b>. Match the network monitoring solution with a description. (Not all options are used.)</b><br />\n<img src=\"assets/exhibits/iao-m13-17/q023-1-680865f1d1.jpg\" alt=\"\" /></p>",
